<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller;use App\Models\{Category,Product};use Illuminate\Http\{RedirectResponse,Request};use Illuminate\Support\Str;use Illuminate\View\View;
class ProductController extends Controller{public function index():View{return view('admin.products.index',['products'=>Product::with('category')->latest()->paginate(15)]);}public function create():View{return view('admin.products.form',['product'=>new Product(),'categories'=>Category::all()]);}public function store(Request $r):RedirectResponse{$data=$this->data($r);$data['slug']=$data['slug']?:Str::slug($data['name']);Product::create($data);return redirect()->route('admin.products.index');}public function edit(Product $product):View{return view('admin.products.form',['product'=>$product,'categories'=>Category::all()]);}public function update(Request $r,Product $product):RedirectResponse{$product->update($this->data($r));return redirect()->route('admin.products.index');}public function destroy(Product $product):RedirectResponse{$product->delete();return back();}private function data(Request $r):array{return $r->validate(['category_id'=>'required|exists:categories,id','name'=>'required','slug'=>'nullable','image'=>'nullable','short_description'=>'nullable','description'=>'nullable','price'=>'required|numeric','discount_price'=>'nullable|numeric','stock'=>'required|integer','brand'=>'nullable','rating'=>'nullable|numeric','is_featured'=>'nullable|boolean','is_active'=>'nullable|boolean'])+['is_featured'=>$r->boolean('is_featured'),'is_active'=>$r->boolean('is_active',true)];}}
